#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define Fin(a) freopen(a,"r",stdin);
#define Fout(a) freopen(a,"w",stdout);
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void rd(bool &x){char ch;do ch=getchar();while(ch!='0'&&ch!='1');x=ch=='1';}
const int N=210;bool mp[N][N],dp[N<<1][N<<1][N];int a[N],stk[N],top;bool vis[N];
inline void Solve()
{
	int n=read();rep(1,n,i)rep(1,n,j)rd(mp[i][j]);
	rep(1,n,i)a[i]=a[i+n]=i;memset(dp,0,sizeof(dp));
	rep(1,n<<1,i)dp[i][i][a[i]]=true;rep(1,n,T)
	{
		for(int l=1,r=T;r<=(n<<1);++l,++r)
		{
			rep(l+1,r,i)if(mp[a[l]][a[i]]&&dp[l+1][r][a[i]]){dp[l][r][a[l]]=true;break;}
			rep(l,r-1,i)if(mp[a[r]][a[i]]&&dp[l][r-1][a[i]]){dp[l][r][a[r]]=true;break;}
			rep(l+1,r-1,i)dp[l][r][a[i]]=dp[l][i][a[i]]&dp[i][r][a[i]];
		}
	}
	memset(vis,0,sizeof(vis));for(int l=1,r=n;r<=(n<<1);++l,++r)rep(1,n,i)vis[i]|=dp[l][r][i];
	drep(n,1,i)if(vis[i])stk[++top]=i;printf("%d\n",top);while(top)printf("%d\n",stk[top--]);
}
int main(){int T=read();while(T--)Solve(); }
